class Solution {
    public int latestTimeCatchTheBus(int[] buses, int[] passengers, int capacity) {
        Arrays.sort(buses);
        Arrays.sort(passengers);
        int i = 0, last = -1;
        for (int bus : buses) {
            int cnt = 0;
            while (i < passengers.length && passengers[i] <= bus && cnt < capacity) {
                last = passengers[i++];
                cnt++;
            }
        }
        if (last == -1) return buses[buses.length - 1];
        return last - (last == buses[buses.length - 1] ? 1 : 0);
    }
}
```
